import{_ as a,c as i,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"플러그인 소개: 기능과 리스크 | Antigravity Auth","description":"Antigravity Auth 플러그인의 핵심 가치와 리스크 알림을 학습하세요. Google OAuth를 통해 Claude와 Gemini 3 모델에 액세스하고, 다중 계정 로드 밸런싱을 지원합니다.","frontmatter":{"title":"플러그인 소개: 기능과 리스크 | Antigravity Auth","sidebarTitle":"이 플러그인이 당신에게 적합한가?","subtitle":"Antigravity Auth 플러그인의 핵심 가치 파악하기","description":"Antigravity Auth 플러그인의 핵심 가치와 리스크 알림을 학습하세요. Google OAuth를 통해 Claude와 Gemini 3 모델에 액세스하고, 다중 계정 로드 밸런싱을 지원합니다.","tags":["시작하기","플러그인 소개","OpenCode","Antigravity"],"order":1},"headers":[],"relativePath":"ko/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md","filePath":"ko/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"}'),e={name:"ko/NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"};function r(n,t,s,h,u,d){return o(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="antigravity-auth-플러그인의-핵심-가치-파악하기" tabindex="-1">Antigravity Auth 플러그인의 핵심 가치 파악하기 <a class="header-anchor" href="#antigravity-auth-플러그인의-핵심-가치-파악하기" aria-label="Permalink to &quot;Antigravity Auth 플러그인의 핵심 가치 파악하기&quot;">​</a></h1><p><strong>Antigravity Auth</strong>는 OpenCode 플러그인으로, Google OAuth 인증을 통해 Antigravity API에 액세스합니다. 익숙한 Google 계정만으로 Claude Opus 4.5, Sonnet 4.5, Gemini 3 Pro/Flash 등 고급 모델을 호출할 수 있으며, API 키 관리가 필요 없습니다. 또한 다중 계정 로드 밸런싱, 이중 쿼터 풀, 자동 세션 복구 등의 기능을 제공하여 고급 모델과 자동 관리가 필요한 사용자에게 적합합니다.</p><h2 id="학습-완료-후-할-수-있는-것" tabindex="-1">학습 완료 후 할 수 있는 것 <a class="header-anchor" href="#학습-완료-후-할-수-있는-것" aria-label="Permalink to &quot;학습 완료 후 할 수 있는 것&quot;">​</a></h2><ul><li>이 플러그인이 자신의 사용 시나리오에 적합한지 판단하기</li><li>플러그인이 지원하는 AI 모델과 핵심 기능 파악하기</li><li>이 플러그인 사용 시의 리스크와 주의사항 명확히 이해하기</li><li>설치 및 구성 계속 진행 여부 결정하기</li></ul><h2 id="현재-당신이-처한-상황" tabindex="-1">현재 당신이 처한 상황 <a class="header-anchor" href="#현재-당신이-처한-상황" aria-label="Permalink to &quot;현재 당신이 처한 상황&quot;">​</a></h2><p>최첨단 AI 모델(Claude Opus 4.5, Gemini 3 Pro 등)을 사용하고 싶지만, 공식 액세스가 제한되어 있습니다. 이러한 모델을 안정적으로 사용할 수 있는 방법을 찾고 있으며, 다음을 원합니다:</p><ul><li>여러 API 키를 수동으로 관리할 필요 없음</li><li>속도 제한 발생 시 자동으로 계정 전환</li><li>대화 중단 후 자동 복구 및 컨텍스트 유지</li></ul><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><p><strong>Antigravity Auth</strong>는 OpenCode 플러그인으로, <strong>Google OAuth 인증</strong>을 통해 Google Antigravity API에 액세스하여, 익숙한 Google 계정만으로 고급 AI 모델을 호출할 수 있게 합니다.</p><p>모든 요청을 프록시하는 것이 아니라, 모델 호출 요청을 <strong>가로채고 변환</strong>하여 Antigravity API로 전달한 후, 응답을 OpenCode가 인식할 수 있는 형식으로 다시 변환합니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><h3 id="지원하는-모델" tabindex="-1">지원하는 모델 <a class="header-anchor" href="#지원하는-모델" aria-label="Permalink to &quot;지원하는 모델&quot;">​</a></h3><table tabindex="0"><thead><tr><th>모델 시리즈</th><th>사용 가능한 모델</th><th>특징</th></tr></thead><tbody><tr><td><strong>Claude</strong></td><td>Opus 4.5, Sonnet 4.5</td><td>확장 사고 모드 지원</td></tr><tr><td><strong>Gemini 3</strong></td><td>Pro, Flash</td><td>Google Search 통합, 확장 사고</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">사고 모드 (Thinking)</p><p>Thinking 모델은 답변을 생성하기 전에 &quot;심층 사고&quot;를 하여 추론 과정을 보여줍니다. 사고 예산을 구성하여 품질과 응답 속도의 균형을 맞출 수 있습니다.</p></div><h3 id="다중-계정-로드-밸런싱" tabindex="-1">다중 계정 로드 밸런싱 <a class="header-anchor" href="#다중-계정-로드-밸런싱" aria-label="Permalink to &quot;다중 계정 로드 밸런싱&quot;">​</a></h3><ul><li><strong>최대 10개의 Google 계정 지원</strong></li><li>속도 제한(429 오류) 발생 시 다음 계정으로 자동 전환</li><li>세 가지 계정 선택 전략: sticky(고정), round-robin(순환), hybrid(지능형 하이브리드)</li></ul><h3 id="이중-쿼터-시스템" tabindex="-1">이중 쿼터 시스템 <a class="header-anchor" href="#이중-쿼터-시스템" aria-label="Permalink to &quot;이중 쿼터 시스템&quot;">​</a></h3><p>플러그인은 <strong>두 개의 독립적인 쿼터 풀</strong>에 동시에 액세스합니다:</p><ol><li><strong>Antigravity 쿼터</strong>: Google Antigravity API에서 제공</li><li><strong>Gemini CLI 쿼터</strong>: Google Gemini CLI에서 제공</li></ol><p>하나의 풀이 속도 제한되면, 플러그인은 자동으로 다른 풀을 시도하여 쿼터 활용을 극대화합니다.</p><h3 id="자동-세션-복구" tabindex="-1">자동 세션 복구 <a class="header-anchor" href="#자동-세션-복구" aria-label="Permalink to &quot;자동 세션 복구&quot;">​</a></h3><ul><li>도구 호출 실패(예: ESC 키로 인한 중단) 감지</li><li>synthetic tool_result를 자동으로 주입하여 대화가 중단되지 않도록 방지</li><li>자동으로 &quot;continue&quot;를 보내 대화를 계속하는 것을 지원</li></ul><h3 id="google-search-통합" tabindex="-1">Google Search 통합 <a class="header-anchor" href="#google-search-통합" aria-label="Permalink to &quot;Google Search 통합&quot;">​</a></h3><p>Gemini 모델에 대해 웹 검색을 활성화하여 사실적 정확성을 높입니다:</p><ul><li><strong>Auto 모드</strong>: 모델이 필요에 따라 검색 여부를 결정</li><li><strong>Always-on 모드</strong>: 매번 검색 수행</li></ul><h2 id="이-플러그인을-사용해야-하는-경우" tabindex="-1">이 플러그인을 사용해야 하는 경우 <a class="header-anchor" href="#이-플러그인을-사용해야-하는-경우" aria-label="Permalink to &quot;이 플러그인을 사용해야 하는 경우&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">다음 시나리오에 적합</p><ul><li>여러 Google 계정이 있어 전체 쿼터를 높이고 싶은 경우</li><li>Claude 또는 Gemini 3의 Thinking 모델이 필요한 경우</li><li>Gemini 모델에 대해 Google Search를 활성화하고 싶은 경우</li><li>API 키를 수동으로 관리하는 대신 OAuth 인증을 선호하는 경우</li><li>속도 제한을 자주 겪어 계정 자동 전환이 필요한 경우</li></ul></div><div class="warning custom-block"><p class="custom-block-title">다음 시나리오에는 적합하지 않음</p><ul><li>Google에서 공식적으로 공개하지 않은 모델이 필요한 경우</li><li>Google ToS 리스크에 매우 민감한 경우(아래 리스크 알림 참조)</li><li>기본 Gemini 1.5 또는 Claude 3 모델만 필요한 경우(공식 인터페이스가 더 안정적)</li><li>WSL, Docker 등에서 브라우저를 열기 어려운 환경에 있는 경우</li></ul></div><h2 id="⚠️-중요-리스크-알림" tabindex="-1">⚠️ 중요 리스크 알림 <a class="header-anchor" href="#⚠️-중요-리스크-알림" aria-label="Permalink to &quot;⚠️ 중요 리스크 알림&quot;">​</a></h2><p>이 플러그인을 사용하는 것은 <strong>Google의 서비스 약관을 위반할 수 있습니다</strong>. 일부 사용자는 Google 계정이 <strong>정지</strong>되거나 <strong>그림자 정지</strong>(명시적 통보 없이 액세스 제한)되었다고 보고했습니다.</p><h3 id="고위험-시나리오" tabindex="-1">고위험 시나리오 <a class="header-anchor" href="#고위험-시나리오" aria-label="Permalink to &quot;고위험 시나리오&quot;">​</a></h3><ul><li>🚨 <strong>완전히 새로운 Google 계정</strong>: 정지 확률이 매우 높음</li><li>🚨 <strong>Pro/Ultra 구독을 막 시작한 계정</strong>: 플래그 지정 및 정지되기 쉬움</li></ul><h3 id="사용-전-확인-사항" tabindex="-1">사용 전 확인 사항 <a class="header-anchor" href="#사용-전-확인-사항" aria-label="Permalink to &quot;사용 전 확인 사항&quot;">​</a></h3><ul><li>이것은 <strong>비공식 도구</strong>이며 Google이 승인하지 않았습니다</li><li>계정이 일시 중단되거나 영구적으로 금지될 수 있습니다</li><li>이 플러그인을 사용하는 모든 리스크는 사용자가 부담합니다</li></ul><h3 id="권장-사항" tabindex="-1">권장 사항 <a class="header-anchor" href="#권장-사항" aria-label="Permalink to &quot;권장 사항&quot;">​</a></h3><ul><li>이 플러그인을 위해 새 계정을 생성하는 대신 <strong>성숙한 Google 계정</strong>을 사용하세요</li><li>중요한 서비스에 바인딩된 계정은 사용하지 마세요</li><li>계정이 정지되면 이 플러그인을 통해 항소할 수 없습니다</li></ul><div class="danger custom-block"><p class="custom-block-title">계정 보안</p><p>모든 OAuth 토큰은 로컬 <code>~/.config/opencode/antigravity-accounts.json</code>에 저장되며, 어떤 서버에도 업로드되지 않습니다. 하지만 컴퓨터 보안을 유지하여 토큰 유출을 방지하세요.</p></div><h2 id="본-강의-요약" tabindex="-1">본 강의 요약 <a class="header-anchor" href="#본-강의-요약" aria-label="Permalink to &quot;본 강의 요약&quot;">​</a></h2><p>Antigravity Auth는 강력한 OpenCode 플러그인으로, Google OAuth를 통해 Claude와 Gemini 3 고급 모델에 액세스할 수 있게 해줍니다. 다중 계정 로드 밸런싱, 이중 쿼터 풀, 자동 세션 복구 등의 기능을 제공하여 고급 모델과 자동 관리가 필요한 사용자에게 적합합니다.</p><p>하지만 반드시 주의하세요: <strong>이 플러그인을 사용하면 계정 정지 리스크가 있습니다</strong>. 중요하지 않은 Google 계정을 사용하고, 계속 설치하기 전에 관련 리스크를 이해하세요.</p><h2 id="다음-강의-예고" tabindex="-1">다음 강의 예고 <a class="header-anchor" href="#다음-강의-예고" aria-label="Permalink to &quot;다음 강의 예고&quot;">​</a></h2><blockquote><p>다음 강의에서는 **<a href="./../../quick-install/">빠른 설치</a>**를 학습합니다.</p><p>학습 내용:</p><ul><li>5분 만에 플러그인 설치 완료</li><li>첫 번째 Google 계정 추가</li><li>설치 성공 여부 확인</li></ul></blockquote>',42)])])}const p=a(e,[["render",r]]);export{c as __pageData,p as default};
